}

// --- Real IntelligentCompletionEngine Implementation ---
namespace IDE {

IntelligentCompletionEngine::IntelligentCompletionEngine() {
    // Initialize completion patterns
    InitializePatterns();
}

void IntelligentCompletionEngine::InitializePatterns() {
    // PowerShell cmdlet patterns
    patterns_["Get-*"] = {"Get-ChildItem", "Get-Content", "Get-Process", "Get-Service"};
    patterns_["Set-*"] = {"Set-Content", "Set-Location", "Set-Variable"};
    patterns_["New-*"] = {"New-Item", "New-Object", "New-Variable"};
    patterns_["Remove-*"] = {"Remove-Item", "Remove-Variable"};
    
    // Common parameters
    patterns_["-*"] = {"-Path", "-Name", "-Value", "-Force", "-Recurse", "-Verbose"};
}

std::vector<CompletionSuggestion> IntelligentCompletionEngine::getCompletions(const CompletionContext& context, int maxSuggestions) {
    std::vector<CompletionSuggestion> completions;
    
    if (context.text.empty() || maxSuggestions <= 0) {
        return completions;
    }
    
    std::wstring prefix = RawrXD::StringToWString(context.text);
    std::wstring lowerPrefix = prefix;
    std::transform(lowerPrefix.begin(), lowerPrefix.end(), lowerPrefix.begin(), ::towlower);
    
    // Match against patterns
    for (const auto& [pattern, suggestions] : patterns_) {
        std::wstring widePattern = RawrXD::StringToWString(pattern);
        
        // Simple wildcard matching
        if (MatchPattern(prefix, widePattern)) {
            for (const auto& sug : suggestions) {
                CompletionSuggestion suggestion;
                suggestion.text = sug;
                suggestion.confidence = 0.8f;
                completions.push_back(suggestion);
                
                if ((int)completions.size() >= maxSuggestions) {
                    return completions;
                }
            }
        }
    }
    
    // Fallback: substring match
    for (const auto& [pattern, suggestions] : patterns_) {
        for (const auto& sug : suggestions) {
            std::wstring wideSug = RawrXD::StringToWString(sug);
            std::wstring lowerSug = wideSug;
            std::transform(lowerSug.begin(), lowerSug.end(), lowerSug.begin(), ::towlower);
            
            if (lowerSug.find(lowerPrefix) == 0) { // Starts with
                // Check for duplicates
                bool exists = false;
                for (const auto& existing : completions) {
                    if (existing.text == sug) {
                        exists = true;
                        break;
                    }
                }
                
                if (!exists) {
                    CompletionSuggestion suggestion;
                    suggestion.text = sug;
                    suggestion.confidence = 0.6f;
                    completions.push_back(suggestion);
                }
            }
        }
    }
    
    return completions;
}

bool IntelligentCompletionEngine::MatchPattern(const std::wstring& text, const std::wstring& pattern) {
    // Simple wildcard matching (* only)
    size_t starPos = pattern.find(L'*');
    if (starPos == std::wstring::npos) {
        return text == pattern;
    }
    
    std::wstring prefix = pattern.substr(0, starPos);
    std::wstring suffix = pattern.substr(starPos + 1);
    
    if (!prefix.empty() && text.find(prefix) != 0) {
        return false;
    }
    
    if (!suffix.empty()) {
        size_t suffixPos = text.rfind(suffix);
        if (suffixPos == std::wstring::npos || suffixPos + suffix.length() != text.length()) {
            return false;
        }
    }
    
    return true;
}

